// Normalize and validate intake form fields
const input = $input.first().json.body || $input.first().json;
const crypto = require('crypto');
const hash = crypto.createHash('sha256')
  .update(`${input.requester_email}-${input.requested_date}-${Date.now()}`)
  .digest('hex')
  .substring(0, 16);

return [{
  json: {
    request_id: `form-${hash}`,
    requester_name: (input.requester_name || '').trim(),
    requester_email: (input.requester_email || '').trim().toLowerCase(),
    requester_organization: (input.requester_organization || '').trim() || null,
    event_name: (input.event_name || '').trim(),
    event_description: (input.event_description || '').trim() || null,
    requested_date: input.requested_date,
    requested_start_time: input.requested_start_time,
    requested_end_time: input.requested_end_time,
    room_requested: (input.room_requested || '').trim() || null,
    estimated_attendees: parseInt(input.estimated_attendees) || null,
    setup_requirements_raw: (input.setup_requirements || '').trim() || null
  }
}];

// Determine calendar availability based on returned events
const events = $input.all();
const formData = $('Validate & Transform').first().json;
const realEvents = events.filter(e => e.json && e.json.id);
const calendar_available = realEvents.length === 0;

return [{
  json: {
    ...formData,
    calendar_available: calendar_available,
    conflicting_events_count: realEvents.length
  }
}];

// Merge agent response with original form data for downstream steps
const agentResult = $input.first().json;
const formData = $('Validate & Transform').first().json;
const calendarData = $('Calendar Availability Result').first().json;

return [{
  json: {
    request_id: agentResult.request_id || formData.request_id,
    decision: agentResult.decision,
    is_eligible: agentResult.is_eligible,
    eligibility_reason: agentResult.eligibility_reason,
    pricing_tier: agentResult.pricing_tier,
    estimated_cost: agentResult.estimated_cost,
    room_assignment: agentResult.room_assignment,
    setup_config: agentResult.setup_config,
    draft_response: agentResult.draft_response,
    errors: agentResult.errors || [],
    calendar_available: calendarData.calendar_available,
    conflicting_events_count: calendarData.conflicting_events_count || 0,
    _form: formData
  }
}];
